// Determine which newsletter file to publish.
// Defaults to current month; override year/month here if publishing a different month.
const now = new Date();
const year = now.getFullYear().toString();
const month = String(now.getMonth() + 1).padStart(2, '0');
const monthName = now.toLocaleString('en-US', { month: 'long' });

return {
  json: {
    year,
    month,
    monthName,
    monthYear: `${monthName} ${year}`,
    obsidianPath: `StPeteMusic/newsletters/${year}/${month}-newsletter.md`,
    newsletterTitle: `St Pete Music Newsletter - ${monthName} ${year}`
  }
};

// Parse the Obsidian API response and validate the newsletter is approved.
// The API returns JSON with .frontmatter and .content fields.
const raw = $input.first().json;
let parsed;
try {
  parsed = typeof raw === 'string' ? JSON.parse(raw) : raw;
} catch (e) {
  throw new Error(`Could not parse Obsidian response: ${e.message}`);
}

const fm = parsed.frontmatter || {};
const content = parsed.content || '';

// Gate: only process approved newsletters
if (fm.status !== 'approved') {
  throw new Error(
    `Newsletter status is "${fm.status}" — change it to "approved" in Obsidian before publishing.`
  );
}

// Extract the HTML body between the ## Newsletter Body HTML header and the next ## header
// The newsletter body HTML is everything after '## Newsletter Body HTML\n' until the next '## '
const bodyMatch = content.match(/##\s+Newsletter Body HTML\s*\n([\s\S]*?)(?:\n##\s|$)/);
const htmlBody = bodyMatch ? bodyMatch[1].trim() : '';

if (!htmlBody) {
  throw new Error('Could not extract HTML body from newsletter. Check the Obsidian file format.');
}

// Extract subject line (the line after '## Campaign Subject Line\n')
const subjectMatch = content.match(/##\s+Campaign Subject Line\s*\n([^\n]+)/);
const subject = subjectMatch ? subjectMatch[1].replace(/^[\s🎵]+/, '').trim() : fm.title;

return {
  json: {
    title: fm.title || '',
    month: fm.month || '',
    sendDate: fm.sendDate || '',
    subject,
    htmlBody,
    obsidianPath: $('Get Month Path').first().json.obsidianPath,
    fullContent: content,
    frontmatter: fm
  }
};

// Build the Listmonk campaign creation payload.
// The htmlBody is already inline-styled HTML from the AI — it's injected into
// the base template via {{ template "content" . }} in Listmonk.

const input = $input.first().json;

// Listmonk campaign payload
const campaign = {
  name: input.title,
  subject: input.subject,
  lists: [3],          // List ID 3 = "St Pete Music Newsletter"
  template_id: 5,      // Template ID 5 = "St Pete Music Monthly newsletter TEMPLATE"
  type: 'regular',
  content_type: 'html',
  body: input.htmlBody,
  status: 'draft',    // Draft — user manually reviews and sends in Listmonk UI
  send_at: null       // null = no scheduled send; user clicks Send in Listmonk
};

return {
  json: {
    ...input,
    listmonkPayload: campaign
  }
};

// Extract campaign ID from Listmonk API response and build updated Obsidian content.
// Listmonk returns: { data: { id: 123, ... } }
const response = $input.first().json;
let campaignId = '';
try {
  const body = response.body || response;
  const data = typeof body === 'string' ? JSON.parse(body) : body;
  campaignId = String((data.data && data.data.id) || data.id || '');
} catch (e) {
  // Non-fatal — campaign was created, ID extraction failed
  campaignId = 'unknown';
}

// Pull original content from upstream
const upstream = $('Parse & Validate').first().json;
const today = new Date().toISOString().split('T')[0];

// Update the YAML frontmatter: status → queued, listmonkCampaignId → actual ID
let updatedContent = upstream.fullContent;
updatedContent = updatedContent
  .replace(/^status:\s*["']?approved["']?/m, 'status: "queued"')
  .replace(/^listmonkCampaignId:\s*["']{0,2}/m, `listmonkCampaignId: "${campaignId}"`);

// If replacement didn't work (edge case), add the field after title line
if (!updatedContent.includes(`listmonkCampaignId: "${campaignId}"`)) {
  updatedContent = updatedContent.replace(
    /^(title:.*)/m,
    `$1\nlistmonkCampaignId: "${campaignId}"`
  );
}

return {
  json: {
    campaignId,
    obsidianPath: upstream.obsidianPath,
    updatedContent,
    title: upstream.title
  }
};

// Final summary output for the n8n execution log
const input = $('Extract Campaign ID').first().json;
return {
  json: {
    success: true,
    message: `✅ Listmonk campaign created as draft (ID: ${input.campaignId}). Go to https://listmonk.stpetemusic.live to review and send.`,
    campaignId: input.campaignId,
    title: input.title
  }
};
